def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-10
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / (capacity + epsilon)
        priority = 0.0
        if ratio > 3:
            base = (ratio ** 5) - np.sin(capacity)
            modifier = 0
            for x in range(1, int(capacity) + 3):
                if x % 4 == 0:
                    modifier += np.tanh(ratio / (x + epsilon))
                elif x % 3 == 0:
                    modifier -= np.exp(-x / (capacity + epsilon))
                else:
                    modifier += np.cos(ratio * x)
            priority = base + modifier * (capacity % 4)
            if capacity % 5 == 0:
                priority *= 1.15
            elif capacity % 2 == 0:
                priority /= 1.07
            else:
                priority += np.sqrt(capacity)
        elif 2 < ratio <= 3:
            priority = (ratio ** 3) * np.log(capacity + 2)
            for m in range(1, int(item*2) + 1):
                if m % 5 == 0:
                    priority += np.sqrt(m / (capacity + 1)) * np.sin(m)
                elif m % 2 == 0:
                    priority -= (m ** 1.5) / (item + epsilon)
                else:
                    priority += np.log(m + ratio + epsilon)
            priority = max(priority, 0) * (0.9 + (capacity % 3)/10)
        elif 1 <= ratio <= 2:
            priority = np.log(ratio + 1) * np.sqrt(capacity)
            accum = 1
            for n in range(1, 7):
                accum *= abs(np.sin(n * ratio)) + np.cos(n / (capacity + 1))
                if accum > 10:
                    accum /= 2
            priority *= accum
            mod = 0
            for k in range(1, int(capacity/2) + 1):
                if k % 2 == 0:
                    mod += np.log(k + 1)
                else:
                    mod -= k ** 0.5
            priority += mod * 0.3
        elif 0.5 < ratio < 1:
            priority = (1 - ratio) ** (-1.5) * np.exp(-capacity / 50)
            sum_val = 0
            for j in range(1, int(capacity) + 1):
                term = ((-1) ** j) * (ratio ** j) / (j + epsilon)
                if j % 3 == 0:
                    term *= np.cos(j)
                sum_val += term
            priority += abs(sum_val) * 0.7
        else:
            priority = 0.5 + item / (capacity + epsilon)
            for z in range(1, int(capacity * 1.5) + 1):
                if z % 7 == 0:
                    priority += np.log(z + ratio + 1)
                elif z % 5 == 0:
                    priority -= np.sqrt(z) / (z + epsilon)
                else:
                    priority += (ratio ** 2) / (z + epsilon)
            if capacity < item:
                diff = item - capacity
                penalty = diff * 20
                for p in range(1, int(diff) + 1):
                    if p % 3 == 0:
                        penalty += np.exp(-p / (diff + epsilon))
                    elif p % 2 == 0:
                        penalty -= np.log(p + 2)
                    else:
                        penalty += p * 0.2
                penalty = max(penalty, 0)
                priority += penalty
        priorities[i] = priority
    return priorities
